// BYPASS LLM - retorna texto fixo pra testar pipeline
let contatoId = null;
let mensagem = '';
try {
  const body = $input.first().json.body || {};
  contatoId = body.contato_id;
  mensagem = body.mensagens || '';
} catch (e) {}

return [{
  json: {
    output: '🤖 TESTE PIPELINE OK!\n\nRecebi: ' + (mensagem || '(vazio)') + '\n\nSe você ta lendo isso, o problema NAO é Router/Evolution, é o LLM/tools.',
    contato_id: contatoId
  }
}];

let out = '';
try {
  const inp = $input.first();
  if (inp && inp.json) {
    out = inp.json.output || inp.json.text || '';
  }
} catch (e) {}
out = String(out || '').trim();
if (!out) out = 'fallback vazio';
let contatoId = null;
try { contatoId = $('Webhook: agent-start').first().json.body.contato_id; } catch (e) {}
return [{ json: { resposta_texto: out, contato_id: contatoId } }];
